import { getContext, setContext } from 'svelte';
const eventsKey = Symbol('threlte-rapier-rigidbody-events');
export const provideRigidBodyEvents = (events) => {
    const context = {
        get current() {
            return events();
        }
    };
    setContext(eventsKey, context);
};
export const useRigidBodyEvents = () => {
    const context = getContext(eventsKey);
    return context ?? { current: {} };
};
const key = Symbol('threlte-rapier-rigidbody');
export const provideRigidbody = (rigidBody) => {
    const context = {
        get current() {
            return rigidBody();
        }
    };
    setContext(key, context);
};
export const useRigidBody = () => {
    const context = getContext(key);
    return context ?? { current: undefined };
};
